def sieve(n):
    if n < 2:
        return []
    is_prime = bytearray(b'\x01')*(n+1)
    is_prime[0:2] = b'\x00\x00'
    for p in range(2, int(n**0.5)+1):
        if is_prime[p]:
            start = p*p
            step = p
            is_prime[start:n+1:step] = b'\x00'*(((n - start)//step)+1)
    return [i for i in range(2, n+1) if is_prime[i]]

